import React, { useEffect, useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap, ZoomControl } from 'react-leaflet';
import L from 'leaflet';
import 'leaflet/dist/leaflet.css';
import { Link } from 'react-router-dom';
import { MoveRight, Star, Navigation } from 'lucide-react';

// Elite Custom Marker Icon
const createCustomIcon = (isActive) => L.divIcon({
    className: 'custom-marker',
    html: `<div class="marker-shell ${isActive ? 'active' : ''}">
            <div class="marker-ring"></div>
            <div class="marker-core"></div>
          </div>`,
    iconSize: [48, 48],
    iconAnchor: [24, 48],
    popupAnchor: [0, -48]
});

const MapRecenter = ({ center, zoom = 13 }) => {
    const map = useMap();
    useEffect(() => {
        if (map) {
            map.flyTo(center, zoom, { duration: 2.5, easeLinearity: 0.1 });
        }
    }, [center, zoom, map]);
    return null;
};

const Map = ({ places, activePlaceId, onMarkerClick }) => {
    const [center, setCenter] = useState([11.2774, 76.2238]);
    const [zoom, setZoom] = useState(13);

    useEffect(() => {
        if (activePlaceId) {
            const activePlace = places.find(p => p.id === activePlaceId);
            if (activePlace) {
                // Wrap in a condition or use a different trigger if possible.
                // For now, specifically centering on active coordinates.
                setCenter([...activePlace.coordinates]);
                setZoom(15);
            }
        }
    }, [activePlaceId, places]);

    return (
        <div className="h-full w-full relative group/map">
            <MapContainer
                center={center}
                zoom={13}
                scrollWheelZoom={true}
                className="h-full w-full z-10 !bg-forest-50"
                zoomControl={false}
            >
                <TileLayer
                    attribution='&copy; CARTO'
                    url="https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png"
                />
                <ZoomControl position="bottomright" />
                <MapRecenter center={center} zoom={zoom} />

                {places.map((place) => (
                    <Marker
                        key={place.id}
                        position={place.coordinates}
                        icon={createCustomIcon(activePlaceId === place.id)}
                        eventHandlers={{
                            click: () => {
                                onMarkerClick(place.id);
                                setCenter(place.coordinates);
                                setZoom(15);
                            },
                        }}
                    >
                        <Popup className="elite-popup" closeButton={false} maxWidth={320}>
                            <div className="w-[320px] overflow-hidden rounded-[40px] bg-white shadow-elite-xl border border-forest-900/5 group/popup overflow-hidden">
                                <div className="h-48 overflow-hidden relative">
                                    <img
                                        src={place.images[0]}
                                        alt={place.name}
                                        className="w-full h-full object-cover transition-transform duration-1000 group-hover/popup:scale-110"
                                    />
                                    <div className="absolute top-6 left-6 flex items-center gap-3">
                                        <div className="bg-forest-950/80 backdrop-blur-md px-4 py-2 rounded-xl text-[8px] font-black tracking-widest text-white border border-white/10 uppercase">
                                            {place.category}
                                        </div>
                                    </div>
                                    <div className="absolute top-6 right-6">
                                        <div className="bg-gold-500 text-forest-950 px-3 py-2 rounded-xl text-[8px] font-black shadow-elite-lg flex items-center gap-2">
                                            <Star size={10} fill="currentColor" />
                                            SIGNATURE
                                        </div>
                                    </div>
                                    <div className="absolute inset-0 bg-gradient-to-t from-forest-950/80 via-forest-950/20 to-transparent opacity-60 group-hover/popup:opacity-80 transition-opacity" />

                                    <div className="absolute bottom-6 left-6 right-6 transform translate-y-4 opacity-0 group-hover/popup:translate-y-0 group-hover/popup:opacity-100 transition-premium flex items-center justify-between">
                                        <span className="text-[10px] font-black text-white uppercase tracking-[0.3em]">View Intelligence</span>
                                        <MoveRight className="text-gold-400" size={16} />
                                    </div>
                                </div>
                                <div className="p-10">
                                    <div className="mb-8">
                                        <h4 className="font-serif font-bold text-forest-950 text-2xl leading-tight mb-2 italic">{place.name}</h4>
                                        <div className="flex items-center gap-3 text-forest-400">
                                            <Navigation size={12} className="text-gold-600" />
                                            <span className="text-[10px] font-black uppercase tracking-widest">{place.location}</span>
                                        </div>
                                    </div>

                                    <div className="flex items-center justify-between pt-8 border-t border-forest-900/5">
                                        <div className="flex flex-col">
                                            <span className="text-[8px] uppercase tracking-widest text-forest-300 font-black mb-1 italic">Price Tier</span>
                                            <span className="text-xs font-black text-forest-950 tracking-widest italic">{place.priceRange}</span>
                                        </div>
                                        <Link to={`/place/${place.slug}`} className="bg-forest-950 text-white px-8 py-3.5 rounded-2xl text-[10px] font-black uppercase tracking-widest hover:bg-gold-500 hover:text-forest-950 transition-premium shadow-elite-lg">
                                            Inquire
                                        </Link>
                                    </div>
                                </div>
                            </div>
                        </Popup>
                    </Marker>
                ))}
            </MapContainer>

            <style>{`
                .elite-popup .leaflet-popup-content-wrapper {
                    padding: 0;
                    background: transparent;
                    box-shadow: none;
                    border-radius: 40px;
                }
                .elite-popup .leaflet-popup-content {
                    margin: 0;
                    width: 320px !important;
                }
                .elite-popup .leaflet-popup-tip-container {
                    display: none;
                }
                
                .marker-shell {
                    position: relative;
                    width: 48px;
                    height: 48px;
                    display: flex;
                    align-items: center;
                    justify-content: center;
                }
                .marker-ring {
                    position: absolute;
                    width: 100%;
                    height: 100%;
                    background: rgba(201, 147, 67, 0.15);
                    border: 1px solid rgba(201, 147, 67, 0.3);
                    border-radius: 50%;
                    animation: marker-pulse 2s infinite ease-out;
                    opacity: 0;
                    z-index: 1;
                }
                .marker-core {
                    width: 24px;
                    height: 24px;
                    background: #1a2a1a;
                    border: 4px solid #fff;
                    border-radius: 50% 50% 50% 0;
                    transform: rotate(-45deg);
                    box-shadow: 0 8px 16px rgba(0,0,0,0.3);
                    transition: all 0.6s cubic-bezier(0.23, 1, 0.32, 1);
                    z-index: 2;
                }
                .marker-shell.active .marker-core {
                    background: #c99343;
                    width: 32px;
                    height: 32px;
                    box-shadow: 0 12px 24px rgba(201, 147, 67, 0.4);
                    border-width: 5px;
                }
                .marker-shell.active .marker-ring {
                    opacity: 1;
                }

                @keyframes marker-pulse {
                    0% { transform: scale(0.5); opacity: 0; }
                    50% { opacity: 0.5; }
                    100% { transform: scale(1.5); opacity: 0; }
                }
            `}</style>
        </div>
    );
};

export default Map;

