import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Menu, X, Search, ChevronDown, MapPin, Utensils, Hotel, Fuel, Hospital, ShoppingBag, Car, Calendar } from 'lucide-react';
import categories from '../../data/categories.json';

const iconMap = {
    MapPin, Utensils, Hotel, Fuel, Hospital, ShoppingBag, Car, Calendar
};

const Navbar = () => {
    const [isOpen, setIsOpen] = useState(false);
    const [isScrolled, setIsScrolled] = useState(false);
    const [activeMegaMenu, setActiveMegaMenu] = useState(null);
    const location = useLocation();

    // Pages that should have a transparent navbar initially
    const hasHero = ['/', '/events'].includes(location.pathname) ||
        location.pathname.startsWith('/place/') ||
        categories.some(cat => location.pathname === `/${cat.slug}`);

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 50);
        };
        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    useEffect(() => {
        setIsOpen(false);
        setActiveMegaMenu(null);
    }, [location.pathname]);

    const navTheme = !hasHero || isScrolled
        ? 'glass-premium py-4 shadow-elite-md text-forest-950'
        : 'bg-transparent py-8 text-white';

    return (
        <nav className={`fixed top-0 left-0 w-full z-50 transition-all duration-700 ease-[cubic-bezier(0.23,1,0.32,1)] ${navTheme}`}>
            <div className="max-w-[1800px] mx-auto px-12 flex items-center justify-between">
                <Link to="/" className="flex items-center space-x-4 group">
                    <span className={`text-xl md:text-3xl font-serif font-bold tracking-tight transition-colors duration-500`}>
                        Discover <span className="text-gold-500 font-light">Nilambur</span>
                    </span>
                </Link>

                {/* Desktop Navigation - Elite Spacing */}
                <div className="hidden lg:flex items-center space-x-12">
                    <div
                        className="relative h-full flex items-center"
                        onMouseEnter={() => setActiveMegaMenu('discover')}
                        onMouseLeave={() => setActiveMegaMenu(null)}
                    >
                        <button className="flex items-center space-x-2 font-black text-[10px] uppercase tracking-[0.4em] transition-colors hover:text-gold-500 py-4">
                            <span>Collection</span>
                            <ChevronDown size={12} className={`transition-transform duration-500 ${activeMegaMenu === 'discover' ? 'rotate-180' : ''}`} />
                        </button>

                        <AnimatePresence>
                            {activeMegaMenu === 'discover' && (
                                <motion.div
                                    initial={{ opacity: 0, y: 20 }}
                                    animate={{ opacity: 1, y: 0 }}
                                    exit={{ opacity: 0, y: 10 }}
                                    transition={{ duration: 0.5, ease: [0.23, 1, 0.32, 1] }}
                                    className="absolute top-full left-1/2 -translate-x-1/2 w-[800px] mt-2 p-10 bg-white rounded-[32px] shadow-elite-xl border border-forest-900/5 grid grid-cols-2 gap-8"
                                >
                                    {categories.map((cat) => {
                                        const Icon = iconMap[cat.icon] || MapPin;
                                        return (
                                            <Link
                                                key={cat.id}
                                                to={`/${cat.slug}`}
                                                className="flex items-start space-x-6 p-6 rounded-2xl hover:bg-forest-50/50 transition-all duration-500 group/item"
                                            >
                                                <div className="p-4 bg-forest-100/50 rounded-xl text-forest-900 group-hover/item:bg-forest-950 group-hover/item:text-white transition-premium">
                                                    <Icon size={24} strokeWidth={1.5} />
                                                </div>
                                                <div className="space-y-2">
                                                    <h4 className="font-serif font-bold text-xl text-forest-950 group-hover/item:text-gold-600 transition-premium italic leading-tight">{cat.name}</h4>
                                                    <p className="text-[11px] text-forest-600/70 font-medium leading-relaxed italic">{cat.description}</p>
                                                </div>
                                            </Link>
                                        )
                                    })}
                                    <div className="col-span-2 pt-8 mt-4 border-t border-forest-100/50 flex items-center justify-between">
                                        <p className="text-[9px] font-black uppercase tracking-[0.3em] text-forest-300 italic">Nilambur Heritage Bureau</p>
                                        <Link to="/explore" className="text-[9px] font-black uppercase tracking-[0.3em] text-gold-600 hover:text-forest-950 transition-colors">Open Interactive Intelligence →</Link>
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>

                    <Link to="/explore" className="font-black text-[10px] uppercase tracking-[0.4em] transition-colors hover:text-gold-500">
                        Explorer
                    </Link>
                    <Link to="/events" className="font-black text-[10px] uppercase tracking-[0.4em] transition-colors hover:text-gold-500">
                        Culture
                    </Link>

                    <div className="flex items-center space-x-10">
                        <Link
                            to="/explore"
                            className="p-3 rounded-full hover:bg-gold-500/10 transition-premium"
                        >
                            <Search size={18} />
                        </Link>

                        <Link to="/explore" className={`btn-primary shadow-elite-md`}>
                            Plan Inquiry
                        </Link>
                    </div>
                </div>

                {/* Mobile Menu Toggle */}
                <button
                    className="lg:hidden p-3 rounded-xl hover:bg-white/10 transition-colors"
                    onClick={() => setIsOpen(!isOpen)}
                >
                    {isOpen ? <X size={24} /> : <Menu size={24} />}
                </button>
            </div>

            {/* Mobile Menu - Premium Overlay */}
            <AnimatePresence>
                {isOpen && (
                    <motion.div
                        initial={{ opacity: 0, height: 0 }}
                        animate={{ opacity: 1, height: 'auto' }}
                        exit={{ opacity: 0, height: 0 }}
                        className="lg:hidden bg-white border-t border-forest-50 shadow-elite-xl overflow-hidden"
                    >
                        <div className="p-10 space-y-4">
                            <div className="grid grid-cols-2 gap-4">
                                {categories.map((cat) => {
                                    const Icon = iconMap[cat.icon] || MapPin;
                                    return (
                                        <Link
                                            key={cat.id}
                                            to={`/${cat.slug}`}
                                            className="flex items-center space-x-4 p-5 rounded-2xl bg-forest-50/50 border border-forest-100/30 hover:bg-forest-100 transition-colors"
                                        >
                                            <Icon size={18} className="text-gold-600" />
                                            <span className="text-[10px] font-black uppercase tracking-widest text-forest-950">{cat.name}</span>
                                        </Link>
                                    )
                                })}
                            </div>
                            <div className="pt-8 mt-4 border-t border-forest-100">
                                <Link to="/explore" className="btn-primary flex items-center justify-center space-x-4">
                                    <Search size={16} />
                                    <span>Initiate Search</span>
                                </Link>
                            </div>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>
        </nav>
    );
};

export default Navbar;

import React, { useState, useEffect, useMemo } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { Search, Map as MapIcon, List, SlidersHorizontal, ChevronLeft, MapPin } from 'lucide-react';
import Map from '../components/explore/Map';
import FilterPanel from '../components/explore/FilterPanel';
import ListingCard from '../components/common/ListingCard';
import placesData from '../data/places.json';

const Explore = () => {
    const [searchParams, setSearchParams] = useSearchParams();
    const initialQuery = searchParams.get('q') || '';
    const [viewMode, setViewMode] = useState('split'); // 'split', 'map', 'list'
    const [searchQuery, setSearchQuery] = useState(initialQuery);
    const [isFilterOpen, setIsFilterOpen] = useState(false);
    const [activeFilters, setActiveFilters] = useState({
        categories: [],
        minRating: 0,
        priceRange: null,
        openNow: false
    });
    const [activePlaceId, setActivePlaceId] = useState(null);

    const filteredPlaces = useMemo(() => {
        return placesData.filter(place => {
            const matchesSearch = place.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                place.location.toLowerCase().includes(searchQuery.toLowerCase());
            const matchesCategory = activeFilters.categories.length === 0 || activeFilters.categories.includes(place.category);
            const matchesRating = place.rating >= activeFilters.minRating;
            const matchesPrice = !activeFilters.priceRange || place.priceRange === activeFilters.priceRange;

            return matchesSearch && matchesCategory && matchesRating && matchesPrice;
        });
    }, [searchQuery, activeFilters]);

    // Update URL when search query changes
    useEffect(() => {
        const newParams = new URLSearchParams(searchParams);
        if (searchQuery) {
            newParams.set('q', searchQuery);
        } else {
            newParams.delete('q');
        }
        setSearchParams(newParams, { replace: true });
    }, [searchQuery, setSearchParams, searchParams]);

    const handleFilterChange = (type, value) => {
        if (type === 'reset') {
            setActiveFilters({
                categories: [],
                minRating: 0,
                priceRange: null,
                openNow: false
            });
            return;
        }

        setActiveFilters(prev => {
            if (type === 'categories') {
                const newCats = prev.categories.includes(value)
                    ? prev.categories.filter(c => c !== value)
                    : [...prev.categories, value];
                return { ...prev, categories: newCats };
            }
            return { ...prev, [type]: value };
        });
    };

    return (
        <div className="flex flex-col h-screen bg-white overflow-hidden pt-20">
            {/* Elite Sub-Nav / Header - The Command Center */}
            <header className="flex-none bg-white border-b border-forest-900/5 px-12 py-8 z-50">
                <div className="max-w-[1800px] mx-auto flex flex-col lg:flex-row lg:items-center justify-between gap-12">
                    <div className="flex items-center space-x-8">
                        <motion.div
                            initial={{ opacity: 0, scale: 0.8 }}
                            animate={{ opacity: 1, scale: 1 }}
                            className="w-16 h-16 bg-forest-950 text-gold-500 rounded-2xl flex items-center justify-center shadow-elite-lg"
                        >
                            <MapPin size={28} strokeWidth={1.5} />
                        </motion.div>
                        <div>
                            <h1 className="text-4xl font-serif font-bold text-forest-950 tracking-tighter italic leading-none">Global <span className="text-gold-600">Discovery</span></h1>
                            <p className="text-[10px] uppercase font-black tracking-[0.6em] text-forest-300 mt-2">Nilambur Intelligence Matrix</p>
                        </div>
                    </div>

                    <div className="flex flex-1 max-w-3xl items-center gap-6">
                        <div className="relative flex-1 group">
                            <Search className="absolute left-8 top-1/2 -translate-y-1/2 text-forest-300 group-hover:text-gold-500 transition-premium" size={20} strokeWidth={1.5} />
                            <input
                                type="text"
                                placeholder="Search the collection..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full pl-20 pr-8 py-6 bg-forest-50 border border-transparent rounded-[32px] text-base font-bold text-forest-900 focus:bg-white focus:border-gold-300 focus:shadow-elite-sm transition-premium placeholder:text-forest-300 placeholder:italic placeholder:font-serif"
                            />
                        </div>

                        <button
                            onClick={() => setIsFilterOpen(true)}
                            className="p-6 bg-white border border-forest-900/10 rounded-2xl shadow-elite-sm text-forest-900 hover:border-gold-400 hover:text-gold-600 transition-premium group"
                        >
                            <SlidersHorizontal size={24} strokeWidth={1.5} className="group-hover:rotate-180 transition-transform duration-1000" />
                        </button>

                        <div className="hidden lg:flex items-center bg-forest-50 p-1.5 rounded-[24px] border border-forest-900/5">
                            {[
                                { id: 'split', icon: MapIcon, label: 'Orchestrated' },
                                { id: 'list', icon: List, label: 'Curation' }
                            ].map(mode => (
                                <button
                                    key={mode.id}
                                    onClick={() => setViewMode(mode.id)}
                                    className={`flex items-center space-x-4 px-8 py-4 rounded-[20px] transition-premium text-[10px] font-black uppercase tracking-[0.3em] ${viewMode === mode.id ? 'bg-forest-950 text-gold-500 shadow-elite-lg' : 'text-forest-400 hover:text-forest-600'}`}
                                >
                                    <mode.icon size={16} strokeWidth={2} />
                                    <span>{mode.label}</span>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            </header>

            <main className="flex-1 relative flex overflow-hidden">
                {/* Listings Section - The Curated Stream */}
                <div className={`flex-1 overflow-y-auto custom-scrollbar bg-white transition-all duration-1000 ease-in-out ${viewMode === 'list' ? 'w-full' : 'w-full lg:w-[40%] xl:w-[35%]'}`}>
                    <div className="p-10 md:p-16 pb-48">
                        <div className="flex items-center justify-between mb-16">
                            <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-forest-300 italic">
                                {filteredPlaces.length} Coordinates Found
                            </h2>
                            <div className="h-px flex-1 mx-10 bg-forest-900/5" />
                        </div>

                        {filteredPlaces.length > 0 ? (
                            <div className={`grid gap-12 ${viewMode === 'list' ? 'grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4' : 'grid-cols-1 md:grid-cols-2 lg:grid-cols-1 xl:grid-cols-2'}`}>
                                {filteredPlaces.map((place, index) => (
                                    <motion.div
                                        key={place.id}
                                        initial={{ opacity: 0, scale: 0.98, y: 30 }}
                                        animate={{ opacity: 1, scale: 1, y: 0 }}
                                        transition={{ delay: index * 0.08, duration: 1 }}
                                        onMouseEnter={() => setActivePlaceId(place.id)}
                                    >
                                        <ListingCard place={place} />
                                    </motion.div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-48">
                                <motion.div
                                    initial={{ opacity: 0, scale: 0.8 }}
                                    animate={{ opacity: 1, scale: 1 }}
                                    className="w-32 h-32 bg-forest-50 rounded-full flex items-center justify-center mx-auto mb-12"
                                >
                                    <Search size={48} className="text-forest-100" strokeWidth={1} />
                                </motion.div>
                                <h3 className="text-4xl font-serif font-bold text-forest-950 mb-6 italic tracking-tight uppercase">Void Detected</h3>
