                                <button
                                    onClick={() => handleFilterChange('reset')}
                                    className="mt-12 btn-ghost text-[11px] hover:text-gold-600"
                                >
                                    Purge All Filters
                                </button>
                            </div>
                        )}
                    </div>
                </div>

                {/* Map Section */}
                <div className={`hidden lg:block transition-all duration-700 ${viewMode === 'list' ? 'w-0' : 'flex-1'}`}>
                    <Map
                        places={filteredPlaces}
