                    >
                        {viewMode === 'map' ? (
                            <>
                                <List size={20} />
                                <span className="text-[10px] font-black uppercase tracking-[0.2em]">Listing View</span>
                            </>
                        ) : (
                            <>
                                <MapIcon size={20} />
                                <span className="text-[10px] font-black uppercase tracking-[0.2em]">Interactive Map</span>
                            </>
                        )}
                    </button>
                </div>

                {/* Full-screen Mobile Map Overlay */}
                <AnimatePresence>
                    {viewMode === 'map' && (
                        <motion.div
                            initial={{ opacity: 0, y: 100 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: 100 }}
                            className="lg:hidden fixed inset-0 z-40 bg-white"
                        >
                            <div className="absolute top-8 left-8 z-50">
                                <button
                                    onClick={() => setViewMode('list')}
                                    className="p-4 bg-white rounded-2xl shadow-elite-md border border-forest-900/5 text-forest-900 hover:text-gold-600 transition-premium"
                                >
                                    <ChevronLeft size={24} />
                                </button>
                            </div>
                            <Map
                                places={filteredPlaces}
                                activePlaceId={activePlaceId}
                                onMarkerClick={setActivePlaceId}
                            />
                        </motion.div>
                    )}
                </AnimatePresence>

                {/* Filter Sidebar Overlay */}
                <AnimatePresence>
                    {isFilterOpen && (
                        <>
                            <motion.div
                                initial={{ opacity: 0 }}
                                animate={{ opacity: 1 }}
                                exit={{ opacity: 0 }}
                                onClick={() => setIsFilterOpen(false)}
                                className="fixed inset-0 bg-forest-950/40 backdrop-blur-md z-[60]"
                            />
                            <motion.div
                                initial={{ x: '100%' }}
                                animate={{ x: 0 }}
                                exit={{ x: '100%' }}
                                transition={{ type: 'spring', damping: 25, stiffness: 200 }}
                                className="fixed right-0 top-0 h-full w-full sm:w-[500px] z-[70] p-6 lg:p-12 overflow-y-auto"
                            >
                                <FilterPanel
                                    activeFilters={activeFilters}
                                    onFilterChange={handleFilterChange}
                                    onClose={() => setIsFilterOpen(false)}
                                />
                            </motion.div>
                        </>
                    )}
                </AnimatePresence>
            </main>
        </div>
    );
};

export default Explore;

