import React, { useMemo, useEffect, useState } from 'react';
import { useParams, Link, Routes, Route, NavLink } from 'react-router-dom';
import places from '../data/places.json';
import { Star, MapPin, Clock, Phone, Globe, ChevronRight, Grid, Info, Navigation, History, Heart, Share2, X, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import MiniMap from '../components/common/MiniMap';

const NavItem = ({ to, icon: Icon, label, slug }) => (
    <NavLink
        to={to}
        end={to === `/place/${slug || ''}`}
        className={({ isActive }) => `
            relative flex items-center space-x-3 px-10 py-5 group transition-premium
            ${isActive ? 'text-forest-950 font-black' : 'text-forest-400 font-bold hover:text-forest-700'}
        `}
    >
        {({ isActive }) => (
            <>
                <Icon size={16} className={isActive ? 'text-gold-600' : ''} />
                <span className="text-[10px] uppercase tracking-[0.3em]">{label}</span>
                <AnimatePresence>
                    {isActive && (
                        <motion.div
                            layoutId="activeTab"
                            className="absolute bottom-0 left-8 right-8 h-1 bg-gold-500 rounded-full"
                        />
                    )}
                </AnimatePresence>
            </>
        )}
    </NavLink>
);

const PlaceDetail = () => {
    const { slug } = useParams();

    const place = useMemo(() =>
        slug ? places.find(p => p.slug === slug) : null,
