        if (!place) return;
        const favorites = JSON.parse(localStorage.getItem('nilambur_favorites') || '[]');
        setIsFavorited(favorites.includes(place.id));
        window.scrollTo(0, 0);
    }, [place?.id]);

    const toggleFavorite = () => {
        if (!place) return;
        const favorites = JSON.parse(localStorage.getItem('nilambur_favorites') || '[]');
