                            <Link to="/explore" className="text-[10px] font-black uppercase tracking-[0.3em] text-white/50 hover:text-gold-400 transition-colors">Explore</Link>
                            <ChevronRight size={12} className="text-white/20" />
                            <span className="text-[10px] font-black uppercase tracking-[0.3em] text-gold-500">{place.name}</span>
                        </nav>
                    </div>
                </div>

                <div className="absolute bottom-24 left-0 w-full z-20">
                    <div className="max-w-[1800px] mx-auto px-12">
