                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        } />

                        <Route path="history" element={
                            <div className="space-y-32">
                                <header className="space-y-12">
                                    <div className="flex items-center space-x-8">
                                        <div className="w-16 h-px bg-gold-400" />
                                        <h2 className="text-[11px] font-black uppercase tracking-[0.6em] text-gold-600 italic">Historical Inheritance</h2>
                                    </div>
                                    <h3 className="section-title text-forest-950 uppercase italic leading-tight">
                                        Legacy of <br /><span className="text-forest-400 not-italic">Timber & Gold</span>
                                    </h3>
                                </header>

                                <div className="space-y-24">
                                    <div className="flex items-center space-x-12 opacity-40">
                                        <div className="w-32 h-px bg-gold-600" />
                                        <p className="text-forest-950 font-serif italic text-3xl leading-tight">"A narrative sculpted from ancient teak and golden sunlight."</p>
                                    </div>
                                    <div className="space-y-20">
                                        <div className="p-20 bg-white border border-forest-900/5 rounded-[80px] shadow-elite-md italic text-forest-900 font-serif space-y-12">
                                            <p className="text-3xl leading-[1.6] font-medium max-w-5xl">
                                                {place.history}
                                            </p>
                                            <div className="pt-12 border-t border-forest-900/5">
                                                <p className="text-3xl leading-relaxed max-w-4xl text-forest-400 italic">
                                                    "Nilambur serves as the spiritual guardian of Kerala's timber heritage. Every visit is a step back into a majestic timeline."
                                                </p>
                                                <p className="text-[10px] uppercase tracking-[0.5em] font-black text-gold-600 mt-8">— Historical Bureau Custodians</p>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        } />
                    </Routes>
                </div>
            </section>

            {/* Lightbox */}
            <AnimatePresence>
                {selectedImg && (
                    <>
                        <motion.div
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            exit={{ opacity: 0 }}
                            onClick={() => setSelectedImg(null)}
                            className="fixed inset-0 bg-forest-950/95 backdrop-blur-3xl z-[100] flex items-center justify-center p-6 sm:p-24"
                        >
                            <button className="absolute top-12 right-12 text-white hover:text-gold-500 transition-premium">
                                <X size={48} />
                            </button>
                            <motion.img
                                initial={{ scale: 0.9, opacity: 0 }}
                                animate={{ scale: 1, opacity: 1 }}
                                exit={{ scale: 0.9, opacity: 0 }}
                                transition={{ type: 'spring', damping: 25 }}
                                src={selectedImg}
                                alt="Gallery Preview"
                                className="max-w-full max-h-full rounded-[48px] shadow-elite-xl border border-white/10"
                                onClick={(e) => e.stopPropagation()}
                            />
                        </motion.div>
                    </>
                )}
            </AnimatePresence>
        </div>
    );
};

export default PlaceDetail;
